"use client";

import Link from "next/link";
import { useState } from "react";

import { FormField, MetadataRow, SectionHeading, Surface, TagChip, TagList } from "@/components/ui/primitives";

type ShowroomTag = {
  id: string;
  name: string;
};

type ShowroomBaseItem = {
  id: string;
  kind: "note" | "link";
  title: string;
  summary: string | null;
  publishedAtLabel: string;
  tags: ShowroomTag[];
};

type ShowroomNoteItem = ShowroomBaseItem & {
  kind: "note";
  excerpt: string;
  slug: string;
};

type ShowroomLinkItem = ShowroomBaseItem & {
  kind: "link";
  url: string;
};

export type PublicShowroomItem = ShowroomNoteItem | ShowroomLinkItem;

type ContentPreviewVariant = "compact" | "balanced" | "feature";

function getDisplayUrl(url: string) {
  try {
    const parsedUrl = new URL(url);
    const pathname = parsedUrl.pathname === "/" ? "" : parsedUrl.pathname;

    return `${parsedUrl.host}${pathname}`;
  } catch {
    return url.replace(/^https?:\/\//, "");
  }
}

function getContentPreviewVariant(item: PublicShowroomItem): ContentPreviewVariant {
  if (item.kind === "note") {
    const hasSummary = Boolean(item.summary?.trim());
    const excerptLength = item.excerpt.trim().length;

    if (hasSummary && (excerptLength > 112 || item.tags.length >= 2)) {
      return "feature";
    }

    if (!hasSummary && excerptLength < 96 && item.tags.length <= 1) {
      return "compact";
    }

    return "balanced";
  }

  const hasSummary = Boolean(item.summary?.trim());
  const displayUrl = getDisplayUrl(item.url);

  if (hasSummary && (displayUrl.length > 32 || item.tags.length >= 2)) {
    return "feature";
  }

  if (!hasSummary && displayUrl.length < 32 && item.tags.length <= 1) {
    return "compact";
  }

  return "balanced";
}

function PublishedContentPreviewCard({ item }: { item: PublicShowroomItem }) {
  const variant = getContentPreviewVariant(item);
  const isNote = item.kind === "note";
  const primaryPreview = isNote ? item.summary?.trim() || item.excerpt.trim() || "Published note" : item.summary?.trim() || "Published link";
  const supportingPreview =
    isNote && variant === "feature" && item.summary?.trim() && item.excerpt.trim() !== item.summary.trim()
      ? item.excerpt.trim()
      : null;

  return (
    <article
      className={`note-preview-card note-preview-card-${variant} public-content-card public-content-card-${item.kind}`}
      data-card-kind={item.kind}
      data-card-variant={variant}
    >
      <div className="note-preview-card-body">
        <h2 className="note-preview-card-title">
          {isNote ? (
            <Link className="note-list-link" href={`/notes/${item.slug}`}>
              {item.title}
            </Link>
          ) : (
            <a className="note-list-link" href={item.url} rel="noopener noreferrer" target="_blank">
              {item.title}
            </a>
          )}
        </h2>
        <div className="note-preview-card-copy">
          <p className="note-preview-card-summary">{primaryPreview}</p>
          {isNote ? (
            supportingPreview ? <p className="note-preview-card-excerpt">{supportingPreview}</p> : null
          ) : (
            <p className="note-preview-card-excerpt public-link-card-url">{getDisplayUrl(item.url)}</p>
          )}
        </div>
      </div>
      <MetadataRow className="note-preview-card-meta">
        <span>{isNote ? "Published note" : "Published link"}</span>
        <span>{item.publishedAtLabel}</span>
      </MetadataRow>
      <TagList aria-label={isNote ? "Published note tags" : "Published link tags"} className="note-preview-card-tags">
        {item.tags.length === 0 ? (
          <TagChip muted>No generated tags</TagChip>
        ) : (
          item.tags.map((tag) => (
            <TagChip key={tag.id}>
              {tag.name}
            </TagChip>
          ))
        )}
      </TagList>
    </article>
  );
}

function getSearchSummary(query: string, visibleCount: number, totalCount: number) {
  if (totalCount === 0) {
    return "No published titles yet.";
  }

  if (!query) {
    return `Showing all ${totalCount} public item${totalCount === 1 ? "" : "s"}.`;
  }

  if (visibleCount === 0) {
    return `No title matches "${query}".`;
  }

  return `Showing ${visibleCount} of ${totalCount} public item${totalCount === 1 ? "" : "s"}.`;
}

export function PublicShowroom({ hasPublishedLinks, items }: { hasPublishedLinks: boolean; items: PublicShowroomItem[] }) {
  const [query, setQuery] = useState("");
  const publishedNotes = items.filter((item) => item.kind === "note").length;
  const normalizedQuery = query.trim().toLocaleLowerCase();
  const filteredItems = normalizedQuery.length === 0 ? items : items.filter((item) => item.title.toLocaleLowerCase().includes(normalizedQuery));
  const publishedCountLabel = hasPublishedLinks
    ? `${items.length} public item${items.length === 1 ? "" : "s"}`
    : `${publishedNotes} published note${publishedNotes === 1 ? "" : "s"}`;
  const listTitle = hasPublishedLinks ? "Published notes and links" : "Published notes";
  const listMeta = normalizedQuery ? `${filteredItems.length} matching title${filteredItems.length === 1 ? "" : "s"}` : "Newest first";
  const emptyStateMessage =
    items.length === 0
      ? "No published notes or links yet. The public site stays empty until the owner explicitly publishes one."
      : hasPublishedLinks
        ? "No published notes or links match this title."
        : "No published notes match this title.";

  return (
    <>
      <Surface className="public-search-shell" density="compact" role="search" tone="panel">
        <div className="search-form public-search-panel">
          <SectionHeading meta="Title-only live filter" title="Search public titles" />
          <div className="public-search-controls">
            <FormField
              className="public-search-field"
              hint="Matches published note and link titles only."
              label="Title filter"
            >
              <input
                aria-label="Search public titles"
                autoComplete="off"
                className="text-input"
                data-testid="public-home-search-input"
                onChange={(event) => setQuery(event.currentTarget.value)}
                placeholder={hasPublishedLinks ? "Filter published notes and links by title" : "Filter published notes by title"}
                type="search"
                value={query}
              />
            </FormField>
            <p className="field-note public-search-summary" data-testid="public-home-search-summary">
              {getSearchSummary(query.trim(), filteredItems.length, items.length)}
            </p>
          </div>
        </div>
      </Surface>

      <div className="public-home-grid">
        <Surface className="note-collection-panel" tone="panel">
          <div className="public-home-shell-head public-hero public-intro-panel">
            <div className="public-home-shell-copy">
              <p className="eyebrow">Public showroom</p>
              <h1>{hasPublishedLinks ? "Notes and links the owner has chosen to share." : "Notes the owner has chosen to share."}</h1>
              <p className="field-note lede">
                {hasPublishedLinks
                  ? "Published notes and published links lead the public surface. Drafts, private links, tags, and AI workflow stay inside the private studio until the owner chooses to publish them."
                  : "Published notes lead the public surface. Drafts, saved links, tags, and AI workflow stay inside the private studio until the owner chooses to publish them."}
              </p>
            </div>
            <div className="public-home-count" aria-label={hasPublishedLinks ? "Public archive size" : "Published note archive size"}>
              <span>Archive</span>
              <strong>{publishedCountLabel}</strong>
            </div>
          </div>
          <SectionHeading meta={listMeta} title={listTitle} />
          {filteredItems.length === 0 ? (
            <p data-testid="public-home-empty-state">{emptyStateMessage}</p>
          ) : (
            <div className="note-list public-note-list public-note-showroom" data-testid="public-home-showroom">
              {filteredItems.map((item) => (
                <PublishedContentPreviewCard key={`${item.kind}-${item.id}`} item={item} />
              ))}
            </div>
          )}
        </Surface>
      </div>
    </>
  );
}

import type { LinkDraftInput } from "@/features/links/types";

const SAFE_LINK_PROTOCOLS = new Set(["http:", "https:"]);

export class LinkValidationError extends Error {
  constructor(readonly code: "invalid-url" | "missing-title") {
    super(code);
    this.name = "LinkValidationError";
  }
}

export function normalizeLinkUrl(url: string) {
  const trimmedUrl = url.trim();

  if (!trimmedUrl) {
    throw new LinkValidationError("invalid-url");
  }

  try {
    const parsedUrl = new URL(trimmedUrl);

    if (!SAFE_LINK_PROTOCOLS.has(parsedUrl.protocol)) {
      throw new LinkValidationError("invalid-url");
    }

    return parsedUrl.toString();
  } catch {
    throw new LinkValidationError("invalid-url");
  }
}

export function normalizeLinkInput(input: LinkDraftInput) {
  const title = input.title.trim();

  if (!title) {
    throw new LinkValidationError("missing-title");
  }

  return {
    url: normalizeLinkUrl(input.url),
    title
  };
}

import "dotenv/config";

import { PrismaBetterSqlite3 } from "@prisma/adapter-better-sqlite3";
import { PrismaClient } from "@prisma/client";
import { expect, test } from "@playwright/test";

const databaseUrl = process.env.DATABASE_URL;

if (!databaseUrl) {
  throw new Error("DATABASE_URL must be set before running public home search tests.");
}

const prisma = new PrismaClient({
  adapter: new PrismaBetterSqlite3({
    url: databaseUrl
  })
});

const seededPublishedNotes = [
  {
    title: "Needle note title",
    slug: "needle-note-title",
    markdown: "# Needle note title",
    excerpt: "A published note whose title should match the public filter.",
    summary: "This note is meant to stay visible when the title matches.",
    publishedAt: new Date("2024-06-14T09:30:00.000Z"),
    tags: ["search"]
  },
  {
    title: "Archive rhythm memo",
    slug: "archive-rhythm-memo",
    markdown: "# Archive rhythm memo",
    excerpt: "The body-needle phrase lives here, but not in the title.",
    summary: null,
    publishedAt: new Date("2024-06-10T09:30:00.000Z"),
    tags: ["reading"]
  }
] as const;

const seededPublishedLinks = [
  {
    title: "Needle link title",
    url: "https://example.com/needle-link-title",
    summary: "A published link whose title should match the public filter.",
    publishedAt: new Date("2024-06-13T09:30:00.000Z"),
    tags: ["search"]
  },
  {
    title: "Field reference shelf",
    url: "https://example.com/field-reference-shelf",
    summary: "The summary-only needle phrase lives here, but not in the title.",
    publishedAt: new Date("2024-06-09T09:30:00.000Z"),
    tags: ["links"]
  }
] as const;

const seededUnpublishedNote = {
  title: "Needle hidden draft",
  slug: "needle-hidden-draft",
  markdown: "# Needle hidden draft",
  excerpt: "This title should never appear in the public showroom.",
  summary: "Unpublished content must stay out of public search results."
} as const;

async function seedPublicSearchContent() {
  const username = process.env.OWNER_USERNAME ?? "owner";
  const owner = await prisma.user.findUnique({
    where: {
      username
    }
  });

  if (!owner) {
    throw new Error(`Owner account '${username}' must exist before public home search tests run.`);
  }

  await prisma.link.deleteMany({
    where: {
      ownerId: owner.id
    }
  });

  await prisma.note.deleteMany({
    where: {
      ownerId: owner.id
    }
  });

  for (const note of seededPublishedNotes) {
    await prisma.note.create({
      data: {
        ownerId: owner.id,
        title: note.title,
        slug: note.slug,
        markdown: note.markdown,
        excerpt: note.excerpt,
        summary: note.summary,
        enrichmentStatus: "ready",
        isPublished: true,
        publishedAt: note.publishedAt,
        createdAt: note.publishedAt,
        updatedAt: note.publishedAt,
        tags: {
          connectOrCreate: note.tags.map((tag) => ({
            where: {
              name: tag
            },
            create: {
              name: tag
            }
          }))
        }
      }
    });
  }

  await prisma.note.create({
    data: {
      ownerId: owner.id,
      title: seededUnpublishedNote.title,
      slug: seededUnpublishedNote.slug,
      markdown: seededUnpublishedNote.markdown,
      excerpt: seededUnpublishedNote.excerpt,
      summary: seededUnpublishedNote.summary,
      enrichmentStatus: "ready",
      isPublished: false
    }
  });

  for (const link of seededPublishedLinks) {
    await prisma.link.create({
      data: {
        ownerId: owner.id,
        title: link.title,
        url: link.url,
        summary: link.summary,
        enrichmentStatus: "ready",
        isPublished: true,
        publishedAt: link.publishedAt,
        createdAt: link.publishedAt,
        updatedAt: link.publishedAt,
        tags: {
          connectOrCreate: link.tags.map((tag) => ({
            where: {
              name: tag
            },
            create: {
              name: tag
            }
          }))
        }
      }
    });
  }
}

test.beforeEach(async () => {
  await seedPublicSearchContent();
});

test.afterAll(async () => {
  await prisma.$disconnect();
});

test("public homepage live search filters mixed published content by title only", async ({ page }) => {
  await page.goto("/");

  const searchInput = page.getByRole("searchbox", { name: "Search public titles" });
  const showroomCards = page.locator("[data-testid='public-home-showroom'] .note-preview-card");

  await expect(searchInput).toBeVisible();
  await expect(page.getByRole("combobox")).toHaveCount(0);
  await expect(showroomCards).toHaveCount(seededPublishedNotes.length + seededPublishedLinks.length);
  await expect(page.getByRole("link", { name: seededPublishedNotes[0].title })).toBeVisible();
  await expect(page.getByRole("link", { name: seededPublishedLinks[0].title })).toBeVisible();

  await searchInput.fill("NEEDLE");

  await expect(page).toHaveURL(/\/$/);
  await expect(showroomCards).toHaveCount(2);
  await expect(page.getByRole("link", { name: seededPublishedNotes[0].title })).toBeVisible();
  await expect(page.getByRole("link", { name: seededPublishedLinks[0].title })).toBeVisible();
  await expect(page.getByRole("link", { name: seededPublishedNotes[1].title })).toHaveCount(0);
  await expect(page.getByRole("link", { name: seededPublishedLinks[1].title })).toHaveCount(0);
  await expect(page.getByRole("link", { name: seededUnpublishedNote.title })).toHaveCount(0);
  await expect(page.getByTestId("public-home-search-summary")).toHaveText("Showing 2 of 4 public items.");

  await searchInput.fill("body-needle");

  await expect(showroomCards).toHaveCount(0);
  await expect(page.getByTestId("public-home-empty-state")).toHaveText("No published notes or links match this title.");

  await searchInput.clear();

  await expect(showroomCards).toHaveCount(seededPublishedNotes.length + seededPublishedLinks.length);
  await expect(page.getByTestId("public-home-search-summary")).toHaveText("Showing all 4 public items.");
});

import Link from "next/link";
import type { ComponentPropsWithoutRef, ElementType, ReactNode } from "react";

function cx(...values: Array<string | false | null | undefined>) {
  return values.filter(Boolean).join(" ");
}

type SurfaceTone = "hero" | "panel" | "card" | "shell" | "inset";

const surfaceToneClasses: Record<SurfaceTone, string> = {
  hero: "hero-card ui-surface ui-surface-hero",
  panel: "panel-card ui-surface ui-surface-panel",
  card: "feature-card ui-surface ui-surface-card",
  shell: "vault-frame ui-surface ui-surface-shell",
  inset: "public-note-metadata ui-surface ui-surface-inset"
};

type SurfaceProps<T extends ElementType> = {
  as?: T;
  tone?: SurfaceTone;
  density?: "default" | "compact";
  children: ReactNode;
  className?: string;
} & Omit<ComponentPropsWithoutRef<T>, "as" | "children" | "className">;

export function Surface<T extends ElementType = "section">({
  as,
  tone = "panel",
  density = "default",
  children,
  className,
  ...props
}: SurfaceProps<T>) {
  const Component = as ?? "section";

  return (
    <Component className={cx(surfaceToneClasses[tone], density === "compact" && "ui-surface-compact", className)} {...props}>
      {children}
    </Component>
  );
}

type SectionHeadingProps = {
  title: ReactNode;
  meta?: ReactNode;
  className?: string;
};

export function SectionHeading({ title, meta, className }: SectionHeadingProps) {
  return (
    <div className={cx("section-heading ui-section-heading", className)}>
      <strong>{title}</strong>
      {meta ? <span className="section-meta">{meta}</span> : null}
    </div>
  );
}

type MetadataRowProps = ComponentPropsWithoutRef<"div"> & {
  leading?: boolean;
};

export function MetadataRow({ children, className, leading = false, ...props }: MetadataRowProps) {
  return (
    <div className={cx("note-meta ui-metadata-row", leading && "note-meta-leading", className)} {...props}>
      {children}
    </div>
  );
}

type TagListProps = ComponentPropsWithoutRef<"div">;

export function TagList({ children, className, ...props }: TagListProps) {
  return (
    <div className={cx("tag-list ui-tag-list", className)} {...props}>
      {children}
    </div>
  );
}

type TagChipProps = ComponentPropsWithoutRef<"span"> & {
  muted?: boolean;
};

export function TagChip({ children, className, muted = false, ...props }: TagChipProps) {
  return (
